import{c as t,Q as s,j as n,m as l}from"./chunks/framework.BIBjCrbN.js";const u=JSON.parse('{"title":"申请材料准备","description":"中国博士申请所需材料清单、各类文书的撰写指南与模板建议","frontmatter":{"title":"申请材料准备","description":"中国博士申请所需材料清单、各类文书的撰写指南与模板建议"},"headers":[],"relativePath":"guide/materials.md","filePath":"guide/materials.md","lastUpdated":1780110618000}'),e={name:"guide/materials.md"};function i(d,a,r,o,p,h){return s(),n("div",null,[...a[0]||(a[0]=[l(`<h1 id="申请材料准备" tabindex="-1">申请材料准备 <a class="header-anchor" href="#申请材料准备" aria-label="Permalink to &quot;申请材料准备&quot;">​</a></h1><h2 id="通用材料清单" tabindex="-1">通用材料清单 <a class="header-anchor" href="#通用材料清单" aria-label="Permalink to &quot;通用材料清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>序号</th><th>材料名称</th><th>要求</th><th>准备时间</th></tr></thead><tbody><tr><td>1</td><td>报考登记表</td><td>网上报名系统自动生成，打印签字</td><td>报名时</td></tr><tr><td>2</td><td>个人陈述</td><td>1000-3000字，阐述学术背景和研究动机</td><td>提前4周</td></tr><tr><td>3</td><td>研究计划书</td><td>3000-5000字，含文献综述、方法设计</td><td>提前6-8周</td></tr><tr><td>4</td><td>个人简历 (CV)</td><td>1-2页，中英文各一份</td><td>持续更新</td></tr><tr><td>5</td><td>硕士成绩单</td><td>官方版本，加盖公章</td><td>提前4周申请</td></tr><tr><td>6</td><td>本科学位证+成绩单</td><td>官方版本</td><td>提前4周申请</td></tr><tr><td>7</td><td>专家推荐信</td><td>2-3封，副教授及以上职称</td><td>提前6周联系</td></tr><tr><td>8</td><td>英语水平证明</td><td>IELTS 6.5+ / TOEFL 90+ / CET-6</td><td>提前备考</td></tr><tr><td>9</td><td>代表性成果</td><td>论文、专利、获奖、项目报告</td><td>—</td></tr><tr><td>10</td><td>身份证/护照复印件</td><td>—</td><td>—</td></tr></tbody></table><h2 id="个人陈述-personal-statement" tabindex="-1">个人陈述 (Personal Statement) <a class="header-anchor" href="#个人陈述-personal-statement" aria-label="Permalink to &quot;个人陈述 (Personal Statement)&quot;">​</a></h2><h3 id="写作结构" tabindex="-1">写作结构 <a class="header-anchor" href="#写作结构" aria-label="Permalink to &quot;写作结构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 开头（10%）— 一句话概括你是谁，为什么申请</span></span>
<span class="line"><span>2. 学术背景（20%）— 本硕学习经历，重点突出相关课程和研究</span></span>
<span class="line"><span>3. 研究经历（40%）— 详细描述科研项目，强调个人贡献和技能</span></span>
<span class="line"><span>4. 研究兴趣与动机（20%）— 为什么对这个方向感兴趣，为什么选择这个导师</span></span>
<span class="line"><span>5. 未来规划（10%）— 短期和长期职业目标</span></span></code></pre></div><h3 id="写作建议" tabindex="-1">写作建议 <a class="header-anchor" href="#写作建议" aria-label="Permalink to &quot;写作建议&quot;">​</a></h3><ul><li><strong>突出海外留学背景的优势</strong>：国际视野、中英双语能力、跨文化科研经验</li><li><strong>量化成果</strong>：如可能，用数据说明（GPA排名、论文影响因子、项目规模等）</li><li><strong>个性化</strong>：针对每个申请学校和导师定制，不要使用通用模板</li><li><strong>展示科研思维</strong>：不仅要写做了什么，更要写为什么这样做、学到了什么</li></ul><h3 id="针对你的经历的关键卖点" tabindex="-1">针对你的经历的关键卖点 <a class="header-anchor" href="#针对你的经历的关键卖点" aria-label="Permalink to &quot;针对你的经历的关键卖点&quot;">​</a></h3><ol><li><strong>帝国理工神经技术硕士</strong> — 世界Top 10名校，专业对口</li><li><strong>脑类器官iPSC研究</strong> — 前沿技术，结合工程与生物</li><li><strong>独立完成硬件+软件原型开发</strong> — 工程实践能力</li><li><strong>UCL医用物理本科</strong> — 扎实的物理和数学基础</li><li><strong>中英双语科研能力</strong> — 文献阅读、论文写作无障碍</li></ol><h2 id="研究计划书-research-proposal" tabindex="-1">研究计划书 (Research Proposal) <a class="header-anchor" href="#研究计划书-research-proposal" aria-label="Permalink to &quot;研究计划书 (Research Proposal)&quot;">​</a></h2><h3 id="写作结构-1" tabindex="-1">写作结构 <a class="header-anchor" href="#写作结构-1" aria-label="Permalink to &quot;写作结构&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 标题 — 简洁明确，反映研究核心问题</span></span>
<span class="line"><span>2. 摘要（200-300字）— 研究问题、方法、意义</span></span>
<span class="line"><span>3. 研究背景与文献综述（约1500字）</span></span>
<span class="line"><span>   - 领域现状</span></span>
<span class="line"><span>   - 存在的问题/知识缺口</span></span>
<span class="line"><span>   - 本研究的切入点</span></span>
<span class="line"><span>4. 研究目标与科学问题（约500字）</span></span>
<span class="line"><span>   - 总体目标</span></span>
<span class="line"><span>   - 具体研究问题/假设</span></span>
<span class="line"><span>5. 研究方法（约1500字）</span></span>
<span class="line"><span>   - 实验设计/技术路线</span></span>
<span class="line"><span>   - 数据采集与分析方案</span></span>
<span class="line"><span>   - 可行性分析</span></span>
<span class="line"><span>6. 预期成果与创新点（约500字）</span></span>
<span class="line"><span>7. 时间规划（约300字）</span></span>
<span class="line"><span>8. 参考文献</span></span></code></pre></div><h3 id="写作建议-1" tabindex="-1">写作建议 <a class="header-anchor" href="#写作建议-1" aria-label="Permalink to &quot;写作建议&quot;">​</a></h3><ul><li>尽量与目标导师的研究方向衔接</li><li>展示对该领域的深入理解</li><li>方法论要具体、可行</li><li>引用该导师的论文（展示你做过功课）</li><li>可以基于你的硕士项目延伸</li></ul><h2 id="推荐信-recommendation-letters" tabindex="-1">推荐信 (Recommendation Letters) <a class="header-anchor" href="#推荐信-recommendation-letters" aria-label="Permalink to &quot;推荐信 (Recommendation Letters)&quot;">​</a></h2><h3 id="推荐人选择" tabindex="-1">推荐人选择 <a class="header-anchor" href="#推荐人选择" aria-label="Permalink to &quot;推荐人选择&quot;">​</a></h3><table tabindex="0"><thead><tr><th>优先级</th><th>推荐人</th><th>理由</th></tr></thead><tbody><tr><td>1</td><td>硕士导师/项目导师</td><td>最了解你近期科研能力的人</td></tr><tr><td>2</td><td>本科导师</td><td>可从长期成长角度评价</td></tr><tr><td>3</td><td>课程教师</td><td>如果某门课成绩突出并有深入交流</td></tr><tr><td>4</td><td>RA的PI/项目负责人</td><td>证明实际工作能力</td></tr></tbody></table><h3 id="如何联系推荐人" tabindex="-1">如何联系推荐人 <a class="header-anchor" href="#如何联系推荐人" aria-label="Permalink to &quot;如何联系推荐人&quot;">​</a></h3><p><strong>邮件要点</strong>：</p><ul><li>礼貌问候，简要回顾你们的关系</li><li>说明你在申请博士，以及申请的方向和学校</li><li>提供你的简历、成绩单和研究计划供参考</li><li>给出明确的截止日期</li><li>附上推荐信模板或提交链接（如有）</li><li>至少提前4周联系</li></ul><h3 id="推荐信应包含的内容" tabindex="-1">推荐信应包含的内容 <a class="header-anchor" href="#推荐信应包含的内容" aria-label="Permalink to &quot;推荐信应包含的内容&quot;">​</a></h3><ul><li>与申请人的关系及认识时间</li><li>对申请人学术能力的评价（独立科研、批判性思维、实验技能）</li><li>具体事例支撑（如某个项目中的表现）</li><li>与其他学生的比较</li><li>对申请人读博的推荐程度</li></ul><h2 id="代表性成果" tabindex="-1">代表性成果 <a class="header-anchor" href="#代表性成果" aria-label="Permalink to &quot;代表性成果&quot;">​</a></h2><p>可以提交的成果类型：</p><ul><li>已发表/在投的学术论文</li><li>本科/硕士毕业论文</li><li>项目技术报告</li><li>发明专利（授权或申请）</li><li>学术会议报告/海报</li><li>竞赛获奖证书</li><li>GRE/GMAT成绩（如有）</li></ul><h2 id="材料提交注意事项" tabindex="-1">材料提交注意事项 <a class="header-anchor" href="#材料提交注意事项" aria-label="Permalink to &quot;材料提交注意事项&quot;">​</a></h2><ul><li><strong>电子版格式</strong>：通常要求PDF格式，注意文件命名规范（如：姓名-材料类型.pdf）</li><li><strong>纸质版邮寄</strong>：使用顺丰/EMS等可追踪的快递，保留快递单号</li><li><strong>文件大小</strong>：注意各校系统对上传文件的大小限制</li><li><strong>彩色扫描</strong>：学位证、成绩单等原件需彩色扫描</li><li><strong>翻译件</strong>：非中文材料需要翻译并公证</li></ul>`,28)])])}const b=t(e,[["render",i]]);export{u as __pageData,b as default};
